suites.command:
python3 -c "from pathlib import Path; import re, sys; root = Path('scripts'); allowed = root / 'workspace-merge-safe.sh'; rx = re.compile(r'^\s*(?:if\s+!\s+)?git\s+merge\b'); violations = [];
for path in sorted(root.rglob('*.sh')):
    if path == allowed:
        continue
    for line_number, line in enumerate(path.read_text(encoding='utf-8').splitlines(), start=1):
        stripped = line.lstrip()
        if stripped.startswith('#'):
            continue
        if rx.search(line):
            violations.append(f'{path}:{line_number}:{stripped}')
if violations:
    print('FAIL: raw git merge found outside workspace-merge-safe.sh')
    print('\n'.join(violations))
    sys.exit(1)
print('PASS: no raw git merge outside workspace-merge-safe.sh')"
